try{window.addEventListener('beforeunload',()=>{})}catch(e){}function layerSearchText(){return (document.getElementById('layerSearch')?.value||'').toLowerCase().trim()}function visibleText(txt){return true}function searchBlob(item){return String([item.label,item.kind,item.source,item.uid,item.type].filter(Boolean).join(' ')).toLowerCase()}function clearSearchSource(src){mapSearchItems=mapSearchItems.filter(x=>x.source!==src)}function addSearchItem(src,kind,label,lat,lon,layer,meta){if(lat==null||lon==null||!layer)return;mapSearchItems.push({id:src+':'+mapSearchItems.length,source:src,kind:kind||src,label:String(label||kind||src),lat:Number(lat),lon:Number(lon),layer,uid:meta?.uid||meta?.id||'',type:meta?.type||'',sourceLabel:meta?.source||src})}function clearMapSearch(){const i=document.getElementById('layerSearch');if(i)i.value='';handleMapSearch()}function handleMapSearch(){renderSearchResults();applySearchStyles()}function searchMatches(item,q){return !q||searchBlob(item).includes(q)}function renderSearchResults(){const box=document.getElementById('searchResults');if(!box)return;const q=layerSearchText();if(!q){box.style.display='none';box.innerHTML='';return}const matches=mapSearchItems.filter(i=>searchMatches(i,q)).slice(0,24);box.style.display='block';box.innerHTML=matches.length?matches.map(i=>`<button class="search-result-item" onclick="chooseSearchItem('${esc(i.id)}')"><span><b>${esc(i.label)}</b><small>${esc(i.kind)} · ${esc(i.sourceLabel)}</small></span><span class="search-result-chip">${esc(i.type||i.source)}</span></button>`).join(''):'<div class="muted" style="padding:8px">No matching map objects.</div>'}function chooseSearchItem(id){const item=mapSearchItems.find(x=>x.id===id);if(!item)return;map.panTo([item.lat,item.lon],{animate:true});setTimeout(()=>{try{item.layer.openPopup&&item.layer.openPopup()}catch(e){}},220)}function applySearchStyles(){const q=layerSearchText();for(const item of mapSearchItems){try{const el=item.layer.getElement&&item.layer.getElement();if(!el)continue;el.classList.remove('search-dim','search-hit');if(q){el.classList.add(searchMatches(item,q)?'search-hit':'search-dim')}}catch(e){}}}function toggleSidebar(){const sb=document.getElementById('sidebar');const tab=document.getElementById('sidebarTab');const banner=document.getElementById('mapStatusBanner');sb.classList.toggle('collapsed');const collapsed=sb.classList.contains('collapsed');if(tab)tab.textContent=collapsed?'›':'‹';if(banner)banner.style.left=collapsed?'66px':(window.matchMedia('(max-width:900px)').matches?'66px':'462px');setTimeout(()=>map&&map.invalidateSize(),220)}async function logoutTakMap(){try{await fetch('/api/tak-map/logout',{method:'POST'});}catch(e){}location.href='/tak-map/login'}
