function pad2(n){return String(n).padStart(2,'0')}
function shortDateTime24(value){try{let d=null;if(value==null||value==='')return'Unknown';if(typeof value==='number'){d=new Date(value>100000000000?value:value*1000)}else{let s=String(value).trim();if(/^\d+$/.test(s)){const n=Number(s);d=new Date(n>100000000000?n:n*1000)}else{d=new Date(s)}}if(!d||isNaN(d.getTime()))return String(value).slice(0,16);return pad2(d.getMonth()+1)+'/'+pad2(d.getDate())+'/'+d.getFullYear()+' '+pad2(d.getHours())+':'+pad2(d.getMinutes())}catch(e){return'Unknown'}}
