function formatDmsPart(v,lat){const hemi=lat?(v>=0?'N':'S'):(v>=0?'E':'W');v=Math.abs(Number(v));const deg=Math.floor(v);const minF=(v-deg)*60;const min=Math.floor(minF);const sec=(minF-min)*60;return deg+'°'+pad2(min)+"'"+sec.toFixed(1)+'"'+hemi}
function latBand(lat){const bands='CDEFGHJKLMNPQRSTUVWX';let i=Math.floor((Number(lat)+80)/8);if(i<0)i=0;if(i>bands.length-1)i=bands.length-1;return bands[i]}
function latLonToUtm(lat,lon){lat=Number(lat);lon=Number(lon);const a=6378137,f=1/298.257223563,k0=.9996,e=Math.sqrt(f*(2-f)),e2=e*e,ep2=e2/(1-e2);const zone=Math.floor((lon+180)/6)+1;const lon0=(zone-1)*6-180+3;const p=Math.PI/180;const phi=lat*p,lam=lon*p,lam0=lon0*p;const N=a/Math.sqrt(1-e2*Math.sin(phi)**2),T=Math.tan(phi)**2,C=ep2*Math.cos(phi)**2,A=Math.cos(phi)*(lam-lam0);const M=a*((1-e2/4-3*e2*e2/64-5*e2**3/256)*phi-(3*e2/8+3*e2*e2/32+45*e2**3/1024)*Math.sin(2*phi)+(15*e2*e2/256+45*e2**3/1024)*Math.sin(4*phi)-(35*e2**3/3072)*Math.sin(6*phi));let E=k0*N*(A+(1-T+C)*A**3/6+(5-18*T+T*T+72*C-58*ep2)*A**5/120)+500000;let Nn=k0*(M+N*Math.tan(phi)*(A*A/2+(5-T+9*C+4*C*C)*A**4/24+(61-58*T+T*T+600*C-330*ep2)*A**6/720));if(lat<0)Nn+=10000000;return{zone,band:latBand(lat),easting:E,northing:Nn}}
function formatUtm(lat,lon){try{const u=latLonToUtm(lat,lon);return u.zone+u.band+' '+Math.round(u.easting)+'E '+Math.round(u.northing)+'N'}catch(e){return Number(lat).toFixed(5)+', '+Number(lon).toFixed(5)}}
function formatMgrs(lat,lon){try{const u=latLonToUtm(lat,lon);const sets=['ABCDEFGH','JKLMNPQR','STUVWXYZ'];const colSet=sets[(u.zone-1)%3];const col=colSet[Math.max(0,Math.min(7,Math.floor(u.easting/100000)-1))]||'Z';const rows='ABCDEFGHJKLMNPQRSTUV';const row=rows[(Math.floor(u.northing/100000)+((u.zone%2)===0?5:0))%20]||'Z';const er=String(Math.floor(u.easting%100000)).padStart(5,'0');const nr=String(Math.floor(u.northing%100000)).padStart(5,'0');return u.zone+u.band+' '+col+row+' '+er+' '+nr}catch(e){return formatUtm(lat,lon)}}
function formatCoordMode(ll){if(!ll)return'Move pointer over map';const lat=Number(ll.lat),lng=Number(ll.lng);if(coordFormatMode==='DMS')return formatDmsPart(lat,true)+' '+formatDmsPart(lng,false);if(coordFormatMode==='UTM')return formatUtm(lat,lng);if(coordFormatMode==='MGRS')return formatMgrs(lat,lng);return lat.toFixed(6)+', '+lng.toFixed(6)}
function updateCoordReadout(ll,pinned){const live=document.getElementById('coordLiveText');const pin=document.getElementById('coordPinnedText');if(live)live.textContent=(pinned?'Pinned: ':'Live: ')+formatCoordMode(ll);if(pin){pin.style.display=pinnedCoordinate?'inline':'none';pin.textContent=pinnedCoordinate?'Pinned '+coordFormatMode:''}}
