function parseCoordinateText(s){const nums=String(s||'').match(/-?\d+(?:\.\d+)?/g)||[];if(nums.length<2)return null;let a=Number(nums[0]),b=Number(nums[1]);if(!Number.isFinite(a)||!Number.isFinite(b))return null;if(Math.abs(a)<=90&&Math.abs(b)<=180)return L.latLng(a,b);if(Math.abs(b)<=90&&Math.abs(a)<=180)return L.latLng(b,a);return null}
function coordGoTo(){const s=prompt('Go to coordinate (lat, lon):',pinnedCoordinate?formatCoordMode(pinnedCoordinate):(lastPointerLatLng?formatCoordMode(lastPointerLatLng):''));const ll=parseCoordinateText(s);if(!ll){if(s!==null)alert('Could not parse coordinate. Use lat, lon.');return}pinnedCoordinate=ll;map.setView(ll,Math.max(map.getZoom(),14));updateCoordReadout(ll,true)}
async function coordSaveLocalPoint(){const ll=pinnedCoordinate||lastPointerLatLng;if(!ll){alert('Pin or hover a coordinate first.');return}const name=(prompt('Save Local Point name:','Coordinate '+shortDateTime24(Date.now()).replace(/[/:]/g,'-'))||'').trim();if(!name)return;try{const feature={type:'FeatureCollection',features:[{type:'Feature',geometry:{type:'Point',coordinates:[Number(ll.lng),Number(ll.lat)]},properties:{name,source:'TAK Map Coordinates',kind:'point',format:coordFormatMode,coordinate:formatCoordMode(ll)}}]};const blob=new Blob([JSON.stringify(feature,null,2)],{type:'application/geo+json'});const file=new File([blob],name.replace(/[\\/:*?"<>|]+/g,'-')+'.geojson',{type:'application/geo+json'});const fd=new FormData();fd.append('files',file,file.name);const r=await fetch('/api/tak-map/import',{method:'POST',body:fd});const j=await r.json();if(!r.ok||!j.ok)throw new Error(j.error||('HTTP '+r.status));lastImports=j.imports||lastImports;await refreshLocalData();drawImportedObjects()}catch(e){alert('Save Local Point failed: '+e)}}
function fmtDistance(m,mode){m=Number(m||0);const ft=m*3.280839895,mi=m/1609.344,km=m/1000;if(mode==='imperial')return mi>=0.1?mi.toFixed(2)+' mi':Math.round(ft)+' ft';if(mode==='metric')return km>=0.1?km.toFixed(2)+' km':Math.round(m)+' m';return mi.toFixed(2)+' mi / '+Math.round(m)+' m'}
function measureSegments(){const seg=[];for(let i=1;i<measurePoints.length;i++){seg.push({a:measurePoints[i-1],b:measurePoints[i],m:map.distance(measurePoints[i-1],measurePoints[i])})}return seg}
function measureSummaryHtml(){const seg=measureSegments();const total=seg.reduce((a,s)=>a+s.m,0);let html='<div class="measure-popup-box" style="color:'+esc(measureTextColor)+'"><h3>Measure Path</h3>';seg.forEach((s,i)=>{html+='<div class="measure-popup-row"><span>Segment '+(i+1)+'</span><b>'+fmtDistance(s.m,'imperial')+' · '+fmtDistance(s.m,'metric')+'</b></div>'});html+='<div class="measure-popup-total">Total: '+(total/1609.344).toFixed(2)+' mi · '+Math.round(total*3.280839895).toLocaleString()+' ft · '+(total/1000).toFixed(2)+' km · '+Math.round(total).toLocaleString()+' m</div></div>';return html}
function drawMeasure(){if(!measureLayer||!map)return;measureLayer.clearLayers();if(!measurePoints.length)return;for(let i=0;i<measurePoints.length;i++){const p=measurePoints[i];const marker=L.marker(p,{interactive:true,draggable:!measureLocked,zIndexOffset:10020,icon:L.divIcon({className:'',html:'<div class="measure-point-dot" style="border-color:#071014;background:'+esc(measureLineColor)+'"></div>',iconSize:[14,14],iconAnchor:[7,7]})}).addTo(measureLayer);marker.on('click',ev=>{try{L.DomEvent.stop(ev)}catch(_){}});marker.on('dragstart',()=>{measureDragIndex=i});marker.on('drag',ev=>{if(measureDragIndex===i){measurePoints[i]=ev.target.getLatLng()}});marker.on('dragend',ev=>{measurePoints[i]=ev.target.getLatLng();measureDragIndex=null;drawMeasure()})}if(measurePoints.length>=2){L.polyline(measurePoints,{color:measureLineColor||'#b9c4c9',weight:3,opacity:.86,dashArray:measureLocked?'6 6':null}).addTo(measureLayer);measureSegments().forEach((s,i)=>{const mid=L.latLng((s.a.lat+s.b.lat)/2,(s.a.lng+s.b.lng)/2);L.marker(mid,{interactive:false,zIndexOffset:10030,icon:L.divIcon({className:'',html:'<div class="measure-seg-label" style="color:'+esc(measureTextColor)+';border-color:'+esc(measureTextColor)+';background:rgba(6,10,14,.94)">'+esc(fmtDistance(s.m,measureUnitsMode))+'</div>',iconAnchor:[0,0]})}).addTo(measureLayer)});L.marker(measurePoints[measurePoints.length-1],{interactive:false,zIndexOffset:10040,icon:L.divIcon({className:'',html:measureSummaryHtml(),iconAnchor:[0,-8]})}).addTo(measureLayer)}}
function setMeasureLineColor(v){measureLineColor=String(v||'#b9c4c9');drawMeasure()}
function setMeasureTextColor(v){measureTextColor=String(v||'#c6d0d5');drawMeasure()}
function measureAddPoint(ll){if(measureLocked){alert('Measurement is locked. Use Resume Edit to add points.');return}measurePoints.push(ll);drawMeasure()}function measureUndo(){if(measureLocked)return alert('Measurement is locked. Use Resume Edit first.');measurePoints.pop();drawMeasure()}function measureClear(){measurePoints=[];measureLocked=false;drawMeasure();updateToolUi()}function measureLock(){if(measurePoints.length<2)return alert('Add at least two measurement points.');measureLocked=true;drawMeasure();updateToolUi()}function measureResume(){measureLocked=false;drawMeasure();updateToolUi()}async function measureCopy(){const seg=measureSegments();if(!seg.length){alert('No measurement to copy.');return}const total=seg.reduce((a,s)=>a+s.m,0);let text='Measurement\n';seg.forEach((s,i)=>{text+='Segment '+(i+1)+': '+fmtDistance(s.m,'imperial')+' / '+fmtDistance(s.m,'metric')+'\n'});text+='Total: '+(total/1609.344).toFixed(2)+' mi / '+Math.round(total*3.280839895)+' ft / '+(total/1000).toFixed(2)+' km / '+Math.round(total)+' m';const ok=await copyText(text);if(!ok)alert(text)}function measureUnitsToggle(){const modes=['all','imperial','metric'];measureUnitsMode=modes[(modes.indexOf(measureUnitsMode)+1)%modes.length];drawMeasure()}
function terrainStatus(msg,bad){try{const el=document.getElementById('terrain3dStatus');if(el){el.textContent=msg;el.style.borderColor=bad?'rgba(255,95,87,.65)':'rgba(53,69,86,.88)';el.style.color=bad?'#ffd2d2':'#c7d1d7'}}catch(e){}}
function loadCssOnce(id,href){return new Promise((resolve,reject)=>{try{if(document.getElementById(id))return resolve();const l=document.createElement('link');l.id=id;l.rel='stylesheet';l.href=href;l.onload=()=>resolve();l.onerror=()=>reject(new Error('Could not load '+href));document.head.appendChild(l)}catch(e){reject(e)}})}
function loadScriptOnce(id,src){return new Promise((resolve,reject)=>{try{if(window.Cesium)return resolve();if(document.getElementById(id)){const wait=()=>window.Cesium?resolve():setTimeout(wait,120);return wait()}const s=document.createElement('script');s.id=id;s.src=src;s.async=true;s.onload=()=>resolve();s.onerror=()=>reject(new Error('Could not load '+src));document.head.appendChild(s)}catch(e){reject(e)}})}
async function loadCesiumAssets(){await loadCssOnce('cesiumCss','https://cdn.jsdelivr.net/npm/cesium@1.119.0/Build/Cesium/Widgets/widgets.css');await loadScriptOnce('cesiumJs','https://cdn.jsdelivr.net/npm/cesium@1.119.0/Build/Cesium/Cesium.js');if(!window.Cesium)throw new Error('Cesium did not load')}
function cesiumBasemapProvider(){const b=basemapById(activeBasemap)||basemapById(config?.default_basemap)||{};const url=String(b.url||'');if(!url.includes('{z}')||!url.includes('{x}')||!url.includes('{y}'))return null;return new Cesium.UrlTemplateImageryProvider({url:url,minimumLevel:Number(b.minZoom||0),maximumLevel:basemapMaxZoom(b),credit:b.attribution||b.label||'Basemap'})}
async function cesiumTerrainProvider(){const url='https://elevation3d.arcgis.com/arcgis/rest/services/WorldElevation3D/Terrain3D/ImageServer';if(Cesium.ArcGISTiledElevationTerrainProvider&&Cesium.ArcGISTiledElevationTerrainProvider.fromUrl)return await Cesium.ArcGISTiledElevationTerrainProvider.fromUrl(url);if(Cesium.ArcGISTiledElevationTerrainProvider)return new Cesium.ArcGISTiledElevationTerrainProvider({url});return new Cesium.EllipsoidTerrainProvider()}
async function ensureTerrain3DViewer(){if(terrain3DViewer)return terrain3DViewer;if(terrain3DLoading)throw new Error('3D terrain is already loading');terrain3DLoading=true;terrainStatus('Loading 3D terrain engine...');try{await loadCesiumAssets();const box=document.getElementById('terrain3dCanvas');if(!box)throw new Error('3D terrain container missing');box.innerHTML='';const imagery=cesiumBasemapProvider();const terrain=await cesiumTerrainProvider();terrain3DViewer=new Cesium.Viewer(box,{animation:false,timeline:false,geocoder:false,homeButton:false,sceneModePicker:false,baseLayerPicker:false,navigationHelpButton:false,fullscreenButton:false,selectionIndicator:false,infoBox:false,shouldAnimate:false,requestRenderMode:true,maximumRenderTimeChange:Infinity,imageryProvider:imagery||undefined,terrainProvider:terrain||undefined});terrain3DViewer.scene.globe.depthTestAgainstTerrain=false;terrain3DViewer.scene.globe.enableLighting=false;terrain3DViewer.scene.screenSpaceCameraController.enableCollisionDetection=true;try{terrain3DViewer.scene.moon.show=false;terrain3DViewer.scene.sun.show=false;terrain3DViewer.shadows=false;terrain3DViewer.scene.shadowMap.enabled=false}catch(_){ }try{terrain3DViewer.camera.moveStart.addEventListener(()=>terrain3DStartMoving());terrain3DViewer.camera.moveEnd.addEventListener(()=>terrain3DEndMoving());terrain3DViewer.scene.preRender.addEventListener(()=>{try{if(terrain3DActive)updateTerrain3DCompass(false)}catch(_){}})}catch(_){ }try{initTerrain3DElevationReadout()}catch(_){ }applyTerrain3DQuality(false);terrainStatus('3D Terrain: Esri World Elevation online terrain · Quality '+terrain3DQuality.toUpperCase());terrain3DLayerReady=true;return terrain3DViewer}catch(e){terrainStatus('3D terrain failed: '+String(e.message||e),true);throw e}finally{terrain3DLoading=false}}

function terrainQualitySettings(q){q=String(q||terrain3DQuality||'medium').toLowerCase();if(q==='low')return {label:'Low',sse:16,movingSse:80,resolution:.70,atmosphere:false,fog:false,labelMeters:12000,clamp:false,deferWhileMoving:true,clusterMeters:26000,clusterDeg:.08,maxFarDots:90,clusterLabels:false,simplifyMeters:22000,maxRouteVerts:90,maxShapeVerts:70};if(q==='high')return {label:'High',sse:5,movingSse:10,resolution:1.0,atmosphere:true,fog:true,labelMeters:65000,clamp:true,deferWhileMoving:false,clusterMeters:90000,clusterDeg:.025,maxFarDots:450,clusterLabels:true,simplifyMeters:80000,maxRouteVerts:650,maxShapeVerts:420};return {label:'Medium',sse:10,movingSse:55,resolution:.80,atmosphere:true,fog:false,labelMeters:28000,clamp:false,deferWhileMoving:true,clusterMeters:42000,clusterDeg:.05,maxFarDots:160,clusterLabels:false,simplifyMeters:36000,maxRouteVerts:160,maxShapeVerts:120}}
function terrainRequestRender(){try{if(terrain3DViewer&&terrain3DViewer.scene&&terrain3DViewer.scene.requestRender)terrain3DViewer.scene.requestRender()}catch(e){}}
function applyTerrain3DQuality(save){try{terrain3DQuality=String(terrain3DQuality||'medium').toLowerCase();if(!['low','medium','high'].includes(terrain3DQuality))terrain3DQuality='medium';if(save!==false)localStorage.setItem('takMapTerrain3DQuality',terrain3DQuality);const sel=document.getElementById('terrain3dQuality');if(sel&&sel.value!==terrain3DQuality)sel.value=terrain3DQuality;if(!terrain3DViewer||!window.Cesium)return;const q=terrainQualitySettings(terrain3DQuality);terrain3DViewer.resolutionScale=q.resolution;terrain3DViewer.scene.globe.maximumScreenSpaceError=q.sse;terrain3DViewer.scene.globe.enableLighting=false;try{terrain3DViewer.scene.skyAtmosphere.show=!!q.atmosphere}catch(_){ }try{terrain3DViewer.scene.fog.enabled=!!q.fog}catch(_){ }try{terrain3DViewer.shadows=false;terrain3DViewer.scene.shadowMap.enabled=false}catch(_){ }terrainStatus('3D Terrain active · Quality '+q.label+' · Terrain detail '+q.sse+' SSE · '+terrain3DLastRenderableCount+' objects');terrainRequestRender()}catch(e){try{console.warn('Terrain quality update failed',e)}catch(_){}}}
function setTerrain3DQuality(v){terrain3DQuality=String(v||'medium').toLowerCase();applyTerrain3DQuality(true);refreshTerrain3DObjects(true,'quality')}
function terrain3DIsDeferredQuality(){return terrainQualitySettings(terrain3DQuality).deferWhileMoving}
function terrain3DStartMoving(){try{terrain3DMoving=true;const q=terrainQualitySettings(terrain3DQuality);if(terrain3DViewer&&q.deferWhileMoving){terrain3DViewer.scene.globe.maximumScreenSpaceError=q.movingSse;try{terrain3DViewer.scene.globe.preloadSiblings=false;terrain3DViewer.scene.globe.preloadAncestors=false;terrain3DViewer.scene.globe.loadingDescendantLimit=0}catch(_){ }terrainStatus('3D Terrain moving · Quality '+q.label+' · terrain/detail loading deferred')}}catch(e){}}
function terrain3DEndMoving(){try{terrain3DMoving=false;applyTerrain3DQuality(false);updateTerrain3DCompass(true);if(terrain3DDeferredRefresh){terrain3DDeferredRefresh=false;scheduleTerrain3DObjectsRefresh(350,true)}else{scheduleTerrain3DObjectsRefresh(450,false)}terrainRequestRender()}catch(e){}}
function terrainCameraDistanceTo(lat,lon){try{if(!terrain3DViewer||!window.Cesium||!isFiniteLatLon(lat,lon))return Number.POSITIVE_INFINITY;const p=Cesium.Cartesian3.fromDegrees(Number(lon),Number(lat));return Cesium.Cartesian3.distance(terrain3DViewer.camera.position,p)}catch(e){return Number.POSITIVE_INFINITY}}
function terrainSimplifyCoordList(pts,closed){try{pts=(pts||[]).filter(p=>p&&isFiniteLatLon(p[0],p[1]));if(pts.length<2)return pts;const cen=[pts.reduce((a,p)=>a+Number(p[0]),0)/pts.length,pts.reduce((a,p)=>a+Number(p[1]),0)/pts.length];const q=terrainQualitySettings(terrain3DQuality);const dist=terrainCameraDistanceTo(cen[0],cen[1]);if(dist<q.simplifyMeters)return pts;const max=Math.max(8,Number(closed?q.maxShapeVerts:q.maxRouteVerts)||120);if(pts.length<=max)return pts;const step=Math.ceil(pts.length/max);const out=[];for(let i=0;i<pts.length;i+=step)out.push(pts[i]);const last=pts[pts.length-1];if(last&&out[out.length-1]!==last)out.push(last);return out}catch(e){return pts||[]}}
function terrainQueueCluster(lat,lon,color,label){try{const q=terrainQualitySettings(terrain3DQuality);terrain3DClusterBuckets=terrain3DClusterBuckets||{};const key=(Math.round(Number(lat)/q.clusterDeg)*q.clusterDeg).toFixed(3)+','+(Math.round(Number(lon)/q.clusterDeg)*q.clusterDeg).toFixed(3);const b=terrain3DClusterBuckets[key]||(terrain3DClusterBuckets[key]={lat:0,lon:0,count:0,color:color||'#c7d1d7',label:label||''});b.lat+=Number(lat);b.lon+=Number(lon);b.count++;terrain3DClusteredCount++}catch(e){}}
function terrainFlushClusters(){try{if(!terrain3DClusterBuckets||!terrain3DViewer||!window.Cesium)return;const q=terrainQualitySettings(terrain3DQuality);const buckets=Object.values(terrain3DClusterBuckets).map(b=>({lat:b.lat/b.count,lon:b.lon/b.count,count:b.count,color:b.color,dist:terrainCameraDistanceTo(b.lat/b.count,b.lon/b.count)})).sort((a,b)=>a.dist-b.dist).slice(0,q.maxFarDots);for(const b of buckets){const size=Math.max(3,Math.min(10,3+Math.sqrt(b.count)));const ent={position:Cesium.Cartesian3.fromDegrees(Number(b.lon),Number(b.lat)),point:{pixelSize:size,color:cesiumColor(b.color||'#c7d1d7',b.count>1?.55:.46),outlineColor:Cesium.Color.BLACK.withAlpha(.55),outlineWidth:1,heightReference:Cesium.HeightReference.CLAMP_TO_GROUND,disableDepthTestDistance:Number.POSITIVE_INFINITY}};if(q.clusterLabels&&b.count>1){ent.label={text:String(b.count),font:'11px sans-serif',fillColor:Cesium.Color.WHITE.withAlpha(.72),outlineColor:Cesium.Color.BLACK.withAlpha(.65),outlineWidth:2,style:Cesium.LabelStyle.FILL_AND_OUTLINE,pixelOffset:new Cesium.Cartesian2(0,-14),showBackground:true,backgroundColor:Cesium.Color.BLACK.withAlpha(.25),heightReference:Cesium.HeightReference.CLAMP_TO_GROUND,disableDepthTestDistance:Number.POSITIVE_INFINITY}}terrain3DViewer.entities.add(ent)}}catch(e){}finally{terrain3DClusterBuckets=null}}
function terrain3DZoom(dir){try{if(!terrain3DViewer||!window.Cesium)return;const h=Math.max(100,terrain3DViewer.camera.positionCartographic.height||2500);if(Number(dir)>0)terrain3DViewer.camera.zoomIn(Math.max(50,h*.28));else terrain3DViewer.camera.zoomOut(Math.max(80,h*.32));terrainRequestRender()}catch(e){}}
function terrain3DResetNorth(){try{if(!terrain3DViewer||!window.Cesium)return;const c=terrain3DViewer.camera.positionCartographic;terrain3DViewer.camera.setView({destination:Cesium.Cartesian3.fromRadians(c.longitude,c.latitude,c.height),orientation:{heading:0,pitch:terrain3DViewer.camera.pitch,roll:0}});updateTerrain3DCompass(true);terrainRequestRender()}catch(e){}}
function updateTerrain3DCompass(force){try{const el=document.getElementById('terrain3dCompassNeedle');if(!el||!terrain3DViewer||!window.Cesium)return;const deg=Cesium.Math.toDegrees(terrain3DViewer.camera.heading||0);el.style.transform='rotate('+(-deg).toFixed(1)+'deg)'}catch(e){}}
function formatTerrainElevation(m){const n=Number(m);if(!Number.isFinite(n))return 'Terrain Elev: —';const ft=n*3.280839895;return 'Terrain Elev: '+Math.round(ft).toLocaleString()+' ft / '+Math.round(n).toLocaleString()+' m'}
function updateTerrain3DElevationFromWindowPosition(pos,force){try{const el=document.getElementById('terrain3dElevation');if(!el||!terrain3DViewer||!window.Cesium||!pos)return;const now=Date.now();if(!force&&now-terrain3DLastElevationMs<180)return;terrain3DLastElevationMs=now;const ray=terrain3DViewer.camera.getPickRay(pos);if(!ray){el.textContent='Terrain Elev: —';return}const cart=terrain3DViewer.scene.globe.pick(ray,terrain3DViewer.scene);if(!cart){el.textContent='Terrain Elev: —';return}const carto=Cesium.Cartographic.fromCartesian(cart);let h=terrain3DViewer.scene.globe.getHeight(carto);if(!Number.isFinite(Number(h)))h=carto.height;el.textContent=formatTerrainElevation(h)}catch(e){}}
function initTerrain3DElevationReadout(){try{if(terrain3DElevationHandler||!terrain3DViewer||!window.Cesium)return;terrain3DElevationHandler=new Cesium.ScreenSpaceEventHandler(terrain3DViewer.scene.canvas);terrain3DElevationHandler.setInputAction(m=>updateTerrain3DElevationFromWindowPosition(m.endPosition,false),Cesium.ScreenSpaceEventType.MOUSE_MOVE);terrain3DElevationHandler.setInputAction(m=>updateTerrain3DElevationFromWindowPosition(m.position,true),Cesium.ScreenSpaceEventType.LEFT_CLICK)}catch(e){}}
function refreshTerrain3DAll(){try{terrain3DLastObjectHash='';refreshTerrain3DBaseLayer();applyTerrain3DQuality(false);refreshTerrain3DObjects(true,'manual-refresh');terrainStatus('3D Terrain refreshed · Quality '+terrainQualitySettings(terrain3DQuality).label)}catch(e){terrainStatus('3D refresh failed: '+String(e.message||e),true)}}

function terrainViewHash(){try{if(!terrain3DViewer||!window.Cesium)return 'none';const r=terrain3DViewer.camera.computeViewRectangle(terrain3DViewer.scene.globe.ellipsoid);if(!r)return 'view';const w=180/Math.PI;return [r.west*w,r.south*w,r.east*w,r.north*w].map(n=>Math.round(n*100)/100).join(',')+'@'+terrain3DQuality}catch(e){return 'view@'+terrain3DQuality}}
function terrain3DDataHash(){try{const parts=[terrainViewHash(),String(state.dataSync),String(state.imported),JSON.stringify(state.live||{})];const fp=o=>{try{const cen=objectCenter(o)||[];const coords=collectCoordPairs(o&&o.coords);const first=coords[0]||[],last=coords[coords.length-1]||[];return [o&& (o.uid||o.id||o.name||o.callsign||o.filename||''),o&&(o.updated||o.timestamp||o.time||o.version||''),cen[0],cen[1],coords.length,first[0],first[1],last[0],last[1],o&&o.color].join(':')}catch(e){return String(Math.random())}};(lastTakMarkers||[]).forEach(o=>parts.push('t:'+fp(o)));(((lastDataSync||{}).objects)||[]).forEach(o=>parts.push('d:'+fp(o)));try{(importedFeatures?importedFeatures():[]).forEach(o=>parts.push('l:'+fp(o)+':'+String(state.local.hidden[String(o._local_id||o.id||o.uid||o.name||'')]||false)))}catch(_){ }return parts.join('|')}catch(e){return String(Date.now())}}
function terrainPointVisible(lat,lon){try{if(!terrain3DViewer||!window.Cesium||!isFiniteLatLon(lat,lon))return true;const r=terrain3DViewer.camera.computeViewRectangle(terrain3DViewer.scene.globe.ellipsoid);if(!r)return true;const rad=Math.PI/180,la=Number(lat)*rad,lo=Number(lon)*rad;let west=r.west,east=r.east,south=r.south,north=r.north;const pad=(north-south+Math.abs(east-west))*.08;south-=pad;north+=pad;west-=pad;east+=pad;if(east<west)return (la>=south&&la<=north&&(lo>=west||lo<=east));return la>=south&&la<=north&&lo>=west&&lo<=east}catch(e){return true}}
function terrainShouldShowLabel(lat,lon){try{if(!terrain3DViewer||!window.Cesium||!isFiniteLatLon(lat,lon))return false;const q=terrainQualitySettings(terrain3DQuality);const p=Cesium.Cartesian3.fromDegrees(Number(lon),Number(lat));const dist=Cesium.Cartesian3.distance(terrain3DViewer.camera.position,p);return dist<q.labelMeters}catch(e){return false}}
function scheduleTerrain3DObjectsRefresh(delay,force){try{if(!terrain3DActive)return;clearTimeout(terrain3DRefreshTimer);terrain3DRefreshTimer=setTimeout(()=>refreshTerrain3DObjects(!!force,'scheduled'),Math.max(250,Number(delay||1000)))}catch(e){}}

function terrainCameraDistance(){try{const z=map?map.getZoom():10;return Math.max(850,Math.min(500000,260000/Math.pow(2,Math.max(0,z-7))))}catch(e){return 12000}}
function syncTerrainCameraFromMap(){try{if(!terrain3DViewer||!map||!window.Cesium)return;const c=map.getCenter();terrain3DViewer.camera.setView({destination:Cesium.Cartesian3.fromDegrees(c.lng,c.lat,terrainCameraDistance()),orientation:{heading:0,pitch:Cesium.Math.toRadians(-58),roll:0}})}catch(e){}}
function syncMapFromTerrainCamera(){try{if(!terrain3DViewer||!map||!window.Cesium)return;const cart=terrain3DViewer.camera.positionCartographic;if(cart){const lat=Cesium.Math.toDegrees(cart.latitude),lon=Cesium.Math.toDegrees(cart.longitude);if(isFiniteLatLon(lat,lon))map.setView([lat,lon],map.getZoom(),{animate:false})}}catch(e){}}
function refreshTerrain3DBaseLayer(){try{if(!terrain3DViewer||!window.Cesium)return;const layers=terrain3DViewer.imageryLayers;layers.removeAll(true);const p=cesiumBasemapProvider();if(p)layers.addImageryProvider(p)}catch(e){try{console.warn('3D basemap refresh failed',e)}catch(_){}}}
function cesiumColor(hex,alpha){try{return Cesium.Color.fromCssColorString(String(hex||'#c7d1d7')).withAlpha(alpha==null?1:alpha)}catch(e){return Cesium.Color.LIGHTGRAY.withAlpha(alpha==null?1:alpha)}}

function terrainPointEntity(lat,lon,label,color){try{if(!isFiniteLatLon(lat,lon)||!terrainPointVisible(lat,lon))return;const q=terrainQualitySettings(terrain3DQuality);const dist=terrainCameraDistanceTo(lat,lon);if(q.clusterMeters&&dist>q.clusterMeters&&q.deferWhileMoving){terrainQueueCluster(lat,lon,color,label);return}const ent={position:Cesium.Cartesian3.fromDegrees(Number(lon),Number(lat)),point:{pixelSize:dist>q.labelMeters?5:8,color:cesiumColor(color||'#c7d1d7',dist>q.labelMeters?.58:.92),outlineColor:Cesium.Color.BLACK.withAlpha(.7),outlineWidth:1,heightReference:Cesium.HeightReference.CLAMP_TO_GROUND,disableDepthTestDistance:Number.POSITIVE_INFINITY}};if(dist<=q.labelMeters&&terrainShouldShowLabel(lat,lon)){ent.label={text:String(label||''),font:'12px sans-serif',fillColor:Cesium.Color.WHITE.withAlpha(.86),outlineColor:Cesium.Color.BLACK.withAlpha(.72),outlineWidth:3,style:Cesium.LabelStyle.FILL_AND_OUTLINE,pixelOffset:new Cesium.Cartesian2(0,-18),showBackground:true,backgroundColor:Cesium.Color.BLACK.withAlpha(.38),heightReference:Cesium.HeightReference.CLAMP_TO_GROUND,disableDepthTestDistance:Number.POSITIVE_INFINITY}}terrain3DViewer.entities.add(ent)}catch(e){}}
function terrainPolylineEntity(pts,label,color){try{pts=(pts||[]).filter(p=>p&&isFiniteLatLon(p[0],p[1]));if(pts.length<2)return;const cen=[pts.reduce((a,p)=>a+Number(p[0]),0)/pts.length,pts.reduce((a,p)=>a+Number(p[1]),0)/pts.length];if(!terrainPointVisible(cen[0],cen[1]))return;pts=terrainSimplifyCoordList(pts,false);const arr=[];pts.forEach(p=>{arr.push(Number(p[1]),Number(p[0]))});terrain3DViewer.entities.add({name:String(label||'Route'),polyline:{positions:Cesium.Cartesian3.fromDegreesArray(arr),width:terrainCameraDistanceTo(cen[0],cen[1])>terrainQualitySettings(terrain3DQuality).simplifyMeters?2:3,material:cesiumColor(color||'#c7d1d7',.86),clampToGround:!!terrainQualitySettings(terrain3DQuality).clamp}})}catch(e){}}
function terrainPolygonEntity(pts,label,color){try{pts=collectCoordPairs(pts).filter(p=>p&&isFiniteLatLon(p[0],p[1]));if(pts.length<3)return;const cen=[pts.reduce((a,p)=>a+Number(p[0]),0)/pts.length,pts.reduce((a,p)=>a+Number(p[1]),0)/pts.length];if(!terrainPointVisible(cen[0],cen[1]))return;pts=terrainSimplifyCoordList(pts,true);const arr=[];pts.forEach(p=>{arr.push(Number(p[1]),Number(p[0]))});const poly={hierarchy:Cesium.Cartesian3.fromDegreesArray(arr),material:cesiumColor(color||'#c7d1d7',.12),outline:true,outlineColor:cesiumColor(color||'#c7d1d7',.62)};if(terrainQualitySettings(terrain3DQuality).clamp)poly.heightReference=Cesium.HeightReference.CLAMP_TO_GROUND;terrain3DViewer.entities.add({name:String(label||'Shape'),polygon:poly})}catch(e){}}
function terrainAddObject(o,source){try{if(!o)return;const label=o.callsign||o.name||o.uid||o.id||source||'Object';const cat=dataSyncCategory(o);if(cat==='Routes'){terrainPolylineEntity(routeCoords(o),label,o.color||'#c7d1d7');return}if(cat==='Shapes / Areas'){terrainPolygonEntity(shapeCoords(o),label,'#c7d1d7');return}const cen=objectCenter(o);if(cen)terrainPointEntity(cen[0],cen[1],label,source==='tak'?'#c7d1d7':'#d0d9de')}catch(e){}}
function refreshTerrain3DObjects(force,reason){try{if(!terrain3DActive||!terrain3DViewer||!window.Cesium)return;const q=terrainQualitySettings(terrain3DQuality);if(terrain3DMoving&&q.deferWhileMoving){terrain3DDeferredRefresh=terrain3DDeferredRefresh||!!force;terrainStatus('3D Terrain moving · object refresh deferred');return}const now=Date.now();const hash=terrain3DDataHash();if(!force&&hash===terrain3DLastObjectHash){terrainStatus('3D Terrain active · Quality '+q.label+' · '+terrain3DLastRenderableCount+' objects · no data changes');return}if(!force&&terrain3DLastObjectRefreshMs&&(now-terrain3DLastObjectRefreshMs)<10000){scheduleTerrain3DObjectsRefresh(10000-(now-terrain3DLastObjectRefreshMs),false);return}terrain3DLastObjectHash=hash;terrain3DLastObjectRefreshMs=now;terrain3DClusterBuckets={};terrain3DClusteredCount=0;terrain3DViewer.entities.removeAll();for(const m of (lastTakMarkers||[])){const kind=m.kind||'cot';if(kind==='eud'&&state.live.euds===false)continue;if(kind==='server_gps'&&state.live.server_gps===false)continue;if(kind!=='eud'&&kind!=='server_gps'&&state.live.cot_markers===false)continue;terrainAddObject(m,'tak')}if(state.dataSync){for(const o of ((lastDataSync||{}).objects||[]))terrainAddObject(o,'datasync')}if(state.imported){for(const f of (importedFeatures?importedFeatures():[])){const lid=String(f._local_id||f.id||f.uid||f.name||'');if(lid&&state.local.hidden[lid])continue;terrainAddObject(f,'local')}}terrainFlushClusters();terrain3DLastRenderableCount=terrain3DViewer.entities.values.length;const clustered=terrain3DClusteredCount?(' · '+terrain3DClusteredCount+' far points clustered'):'';terrainStatus('3D Terrain active · Esri World Elevation · Quality '+q.label+' · '+terrain3DLastRenderableCount+' visible objects'+clustered);terrainRequestRender()}catch(e){terrainStatus('3D object render failed: '+String(e.message||e),true)}}
async function enableTerrain3D(){try{const pane=document.getElementById('terrain3dPane');if(pane)pane.classList.add('active');terrain3DActive=true;terrain3DLastObjectHash='';updateToolUi();await ensureTerrain3DViewer();setTimeout(()=>{try{terrain3DViewer.resize();syncTerrainCameraFromMap();refreshTerrain3DBaseLayer();applyTerrain3DQuality(false);refreshTerrain3DObjects(true,'enable')}catch(e){}},80)}catch(e){terrain3DActive=false;const pane=document.getElementById('terrain3dPane');if(pane)pane.classList.remove('active');updateToolUi();alert('3D Terrain could not start: '+String(e.message||e))}}
