function parseBasemapXmlText(txt,nameHint){const doc=new DOMParser().parseFromString(String(txt||''),'text/xml');const textOf=(tag)=>{const n=doc.getElementsByTagName(tag)[0];return n?n.textContent.trim():''};let label=textOf('name')||textOf('title')||nameHint||'Custom basemap';let url=textOf('url')||textOf('URL')||textOf('serverUrl')||textOf('tileUrl')||'';if(!url){const all=[...doc.getElementsByTagName('*')].map(n=>String(n.textContent||'').trim()).find(v=>/^https?:\/\//i.test(v));url=all||''}if(url&&!/[{]z[}].*[{]y[}].*[{]x[}]|\/tile\//i.test(url)){url=url.replace(/\/$/,'')+'/tile/{z}/{y}/{x}'}if(!url)throw new Error('No tile URL found in XML.');return {id:'custom_xml_'+Date.now(),label,group:'Custom',url,minZoom:0,maxZoom:19,attribution:label}}
function renderCustomBasemapStatus(){const el=document.getElementById('customBasemapStatus');if(el)el.textContent=customBasemapImportStatus||''}
