async function importBasemapXmlFiles(){const inp=document.getElementById('basemapXmlInput');const files=[...(inp?.files||[])];if(!files.length)return;const list=loadCustomBasemaps();let added=0;for(const file of files){try{const txt=await file.text();const b=parseBasemapXmlText(txt,file.name.replace(/\.[^.]+$/,''));list.push(b);added++}catch(e){customBasemapImportStatus='Import failed for '+file.name+': '+e.message}}saveCustomBasemaps(list);applyCustomBasemaps();renderBasemaps();customBasemapImportStatus=added?('Added '+added+' custom basemap'+(added===1?'':'s')+'.'):customBasemapImportStatus;renderCustomBasemapStatus()}
