function updateSendSelectedCount(){const f=document.getElementById('sendFooterCount');const b=document.getElementById('sendConfirmBtn');if(activeSendMode==='live-basemap'||activeSendMode==='offline'||activeSendMode==='local-data-publish'){const sel=document.getElementById('sendMissionSelect');const mission=(sel&&sel.value)||'';if(f)f.textContent=mission?'Data Sync Mission: '+mission:'Select a Data Sync Mission';if(b)b.textContent='Publish';return}const total=sendEudTargets.length;let sel=0;document.querySelectorAll('[data-send-eud]').forEach(cb=>{if(cb.checked)sel++});if(f)f.textContent=total+' online EUD'+(total===1?'':'s')+' found';if(b)b.textContent='Send ('+sel+')'}
function sendModalBackdrop(ev){if(ev.target&&ev.target.id==='sendModal')closeSendModal()}
function closeSendModal(){const el=document.getElementById('sendModal');if(el)el.classList.remove('active');activeSendMapId='';activeSendBasemapId='';activeSendMode='offline';sendEudTargets=[];sendMissionTargets=[]}
async function loadSendTargets(){const rows=document.getElementById('sendEudRows');const status=document.getElementById('sendStatus');try{if(rows)rows.innerHTML='<div class="muted">Loading EUDs from OpenTAKServer...</div>';const r=await fetch('/api/tak-map/euds?send=1&online=1&fresh=1&_='+Date.now(),{cache:'no-store'});const j=await apiJsonResponse(r);sendEudTargets=(j.euds||[]).filter(e=>validSendTarget(e)&&onlineSendTarget(e));if(rows){rows.innerHTML=sendEudTargets.length?sendEudTargets.map((e,i)=>`<label class="send-eud-row"><input type="checkbox" data-send-eud="${i}" onchange="updateSendSelectedCount()"><span class="send-eud-main"><b>${esc(e.callsign||'EUD')}</b><small>${esc(sendCoordLine(e))}</small><small>Team: ${esc(e.team||'unknown')}</small></span><span><span class="send-eud-client">${esc(e.client_label||e.client||'ATAK')}</span><br><span class="send-eud-status">${esc(e.status||'Recent')}</span></span></label>`).join(''):'<div class="muted">No online EUDs were detected. Confirm the EUD is connected and has reported location within the last 3 minutes.</div>'}if(status)status.textContent='';updateSendSelectedCount()}catch(e){sendEudTargets=[];if(rows)rows.innerHTML='<div class="danger">Could not load EUDs: '+esc(e)+'</div>';if(status)status.textContent='';updateSendSelectedCount()}}
async function loadSendMissions(preferred){const rows=document.getElementById('sendEudRows');const status=document.getElementById('sendStatus');const preferredName=preferred||'';try{if(rows)rows.innerHTML='<div class="muted">Loading Data Sync Missions...</div>';let missions=[];try{const r=await fetch('/api/tak-map/data-sync?_='+Date.now(),{cache:'no-store'});const j=await apiJsonResponse(r);missions=(j.missions||[]).map(m=>({name:missionNameFromRow(m),guid:m.guid||'',raw:m})).filter(m=>m.name)}catch(e){missions=[]}sendMissionTargets=missions;const selectedName=(preferredName&&missions.some(m=>m.name===preferredName))?preferredName:(missions[0]?.name||'');const opts=missions.map(m=>`<option value="${esc(m.name)}" ${m.name===selectedName?'selected':''}>${esc(m.name)}</option>`).join('');if(rows)rows.innerHTML=`<div class="send-map-summary"><b>Data Sync Mission/Feed</b><br><small>Publish this package into an existing Data Sync Mission. EUDs must have Data Sync installed and be subscribed to the selected mission/feed.</small><br>${missions.length?`<select id="sendMissionSelect" class="select" onchange="updateSendSelectedCount()">${opts}</select>`:'<div class="danger">No Data Sync Missions found. Create or subscribe to a mission/feed in ATAK Data Sync first.</div>'}</div>`;if(status)status.textContent='';updateSendSelectedCount()}catch(e){if(rows)rows.innerHTML='<div class="danger">Could not load missions: '+esc(e)+'</div>';if(status)status.textContent='';updateSendSelectedCount()}}
function selectedMissionName(){const sel=document.getElementById('sendMissionSelect');return (sel&&sel.value)?sel.value:''}
function openSendOfflineMap(id){activeSendMode='offline';activeSendMapId=id;const m=(offlineMaps||[]).find(x=>String(x.id)===String(id))||{};const modal=document.getElementById('sendModal');const title=document.querySelector('#sendModal h3');const name=document.getElementById('sendMapName');const details=document.getElementById('sendMapDetails');const status=document.getElementById('sendStatus');if(title)title.textContent='Publish Offline Map';if(name)name.textContent='Publish this offline map package to a Data Sync Mission/Feed.';const mb=((Number(m.package_size_bytes||m.size_bytes||0))/(1024*1024));const sizeTxt=mb>0?mb.toFixed(mb>=10?1:2)+' MB':'Unknown size';const zmin=(m.min_zoom??m.minZoom??'—');const zmax=(m.max_zoom??m.maxZoom??'—');const base=m.source_label||m.source_basemap_label||m.basemap_label||m.source_basemap||m.basemap||m.source_id||'Unknown basemap';if(details)details.innerHTML=`<div class="send-map-summary"><b>${esc(m.name||m.filename||'Offline map')}</b><br>Basemap: ${esc(base)}<br>Size: ${esc(sizeTxt)}<br>Zoom levels: ${esc(zmin)}–${esc(zmax)}</div>`;if(status)status.textContent='';if(modal)modal.classList.add('active');loadSendMissions('')}
function openSendLiveBasemapSource(){activeSendMode='live-basemap';activeSendMapId='';activeSendBasemapId=activeBasemap;const b=basemapById(activeBasemap)||{};const modal=document.getElementById('sendModal');const title=document.querySelector('#sendModal h3');const name=document.getElementById('sendMapName');const details=document.getElementById('sendMapDetails');const status=document.getElementById('sendStatus');if(title)title.textContent='Publish Basemap';if(name)name.textContent='Publish an ATAK mapsource XML for '+(b.label||'current basemap')+' to a Data Sync Mission/Feed.';if(details)details.innerHTML='';if(status)status.textContent='';if(modal)modal.classList.add('active');loadSendMissions('')}
async function pollSendStatus(sendId){const status=document.getElementById('sendStatus');if(!sendId)return;let tries=0;const tick=async()=>{tries++;try{const r=await fetch('/api/tak-map/offline-send-status?id='+encodeURIComponent(sendId),{cache:'no-store'});const j=await apiJsonResponse(r);if(j.ok){const delivered=Number(j.delivered||0);const total=(j.targets||[]).length;if(status)status.textContent='Sent fileshare request. Delivered '+delivered+' of '+total+' EUD(s).';if(total&&delivered>=total){offlineMaps=(await (await fetch('/api/tak-map/offline-maps',{cache:'no-store'})).json()).maps||offlineMaps;renderOfflineMapRows();return}}}catch(e){}if(tries<12)setTimeout(tick,2500)};setTimeout(tick,1800)}
async function confirmSendOfflineMap(){const status=document.getElementById('sendStatus');try{const mission=selectedMissionName();if(activeSendMode==='local-data-publish'){if(!mission){if(status)status.innerHTML='<span class="danger">Select a Data Sync Mission.</span>';return}if(status)status.textContent='Publishing local data package to Data Sync Mission...';const r=await fetch('/api/tak-map/local-data-mission-publish',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({ids:activeLocalSendIds,kind:activeLocalSendKind,missionName:mission,serverHost:location.hostname})});const j=await apiJsonResponseAllowFalse(r);if(status){const diag=j.diag_paths&&j.diag_paths.json?(' Diagnostics: '+j.diag_paths.json):'';status.textContent=(j.message||j.error||'Local Data publish finished.')+diag}if(j.ok){forceDataSyncSync('mission-publish-local-data')}return}if(!mission){if(status)status.innerHTML='<span class="danger">Select a Data Sync Mission.</span>';return}if(activeSendMode==='live-basemap'){if(status)status.textContent='Publishing basemap package to Data Sync Mission...';const r=await fetch('/api/tak-map/live-basemap-source-mission-publish',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({basemap_id:activeSendBasemapId,missionName:mission,dashboardOrigin:dashboardHttpsOrigin(),serverHost:location.hostname})});const j=await apiJsonResponseAllowFalse(r);if(status){const diag=j.diag_paths&&j.diag_paths.json?(' Diagnostics: '+j.diag_paths.json):'';status.textContent=(j.message||j.error||'Mission publish finished.')+diag}if(j.ok){forceDataSyncSync('mission-publish-basemap')}return}if(!activeSendMapId)return;if(status)status.textContent='Publishing offline map package to Data Sync Mission...';const r=await fetch('/api/tak-map/offline-mission-publish',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({id:activeSendMapId,missionName:mission,serverHost:location.hostname})});const j=await apiJsonResponseAllowFalse(r);offlineMaps=j.maps||offlineMaps;applyOfflineBasemaps();renderOfflineMapRows();renderBasemaps();if(status){const diag=j.diag_paths&&j.diag_paths.json?(' Diagnostics: '+j.diag_paths.json):'';status.textContent=(j.message||j.error||'Mission publish finished.')+diag}if(j.ok){forceDataSyncSync('mission-publish-offline')}}catch(e){if(status)status.innerHTML='<span class="danger">Publish failed: '+esc(e)+'</span>'}}
function openLocalDataSend(kind,ids){activeSendMode='local-data';activeLocalSendKind=kind;activeLocalSendIds=ids.slice();const modal=document.getElementById('sendModal');const title=document.querySelector('#sendModal h3');const name=document.getElementById('sendMapName');const details=document.getElementById('sendMapDetails');const status=document.getElementById('sendStatus');if(title)title.textContent='Send Local Data';if(name)name.textContent='Select EUDs to receive '+ids.length+' '+kind+' item(s).';if(details)details.innerHTML='<div class="send-map-summary">Type: '+esc(kind)+'<br>Selected: '+esc(ids.length)+'</div>';if(status)status.textContent='';if(modal)modal.classList.add('active');loadSendTargets()}
function localDataKindForFeature(f){const s=String(f?.kind||f?.geometry||f?.geometry_type||f?.type||'').toLowerCase();if(s.includes('route')||s.includes('track')||s.includes('linestring')||s.includes('line string'))return'routes';if(s.includes('polygon')||s.includes('shape')||s.includes('area')||s.includes('rectangle')||s.includes('ellipse')||s.includes('circle'))return'shapes';return'points'}function localDataSets(){const sets={routes:[],points:[],shapes:[]};try{for(const f of importedFeatures()){const id=String(f._local_id||f.id||f.uid||f.name||('local-'+Math.random())).trim();const kind=localDataKindForFeature(f);const item={id,name:String(f.name||f.callsign||f.title||f.uid||id),source:String(f.import_name||f.source||'Imported'),shown:state.local.hidden[id]?false:true,feature:f};sets[kind].push(item)}}catch(e){try{console.warn('localDataSets failed',e)}catch(_){}}return sets}function selectedLocal(kind){try{return Object.keys(state.local[kind]||{}).filter(id=>!!state.local[kind][id])}catch(e){return[]}}function localTypeLabel(kind,count){const base={points:'point',routes:'route',shapes:'shape'}[kind]||'item';return count===1?base:base+'s'}function localSelectedLabel(kind,count){return count+' '+localTypeLabel(kind,count)+' selected'}function toggleLocalSection(kind){try{state.localCollapsed[kind]=!state.localCollapsed[kind];saveTakMapUiPrefs();renderLocalDataRows()}catch(e){try{console.warn('toggleLocalSection failed',e)}catch(_){}}}function unselectLocalSection(kind,ev){try{if(ev)ev.stopPropagation();state.local[kind]={};renderLocalDataRows()}catch(e){}}function toggleLocalItem(kind,id,on){try{state.local[kind]=state.local[kind]||{};state.local[kind][id]=!!on;renderLocalDataRows()}catch(e){try{console.warn('toggleLocalItem failed',e)}catch(_){}}}function localDataFeatureById(id){try{return importedFeatures().find(f=>String(f._local_id||f.id||f.uid||f.name)===String(id))||null}catch(e){return null}}function localDataExportFilename(kind,feats){try{let base='tak-map-local-'+kind;if((feats||[]).length===1){const f=feats[0]||{};base=String(f.name||f.callsign||f.title||f.uid||base)}else if((feats||[]).length>1){base='tak-map-local-'+localTypeLabel(kind,(feats||[]).length)+'-'+(feats||[]).length+'-items'}base=base.replace(/[\/:*?"<>|]+/g,'-').replace(/\n+/g,' ').trim();base=base.replace(/\.(kml|kmz|gpx|geojson|json|zip)$/i,'').trim();base=base.replace(/[. ]+$/,'')||('tak-map-local-'+kind);return base+'.geojson'}catch(e){return 'tak-map-local-'+kind+'.geojson'}}function downloadLocalData(kind,ids){try{const feats=(ids||[]).map(localDataFeatureById).filter(Boolean);const gj={type:'FeatureCollection',features:feats.map(f=>{let geom=null;const coords=Array.isArray(f.coords)?f.coords:null;if(coords&&coords.length){const k=localDataKindForFeature(f);if(k==='points')geom={type:'Point',coordinates:[Number(f.lon),Number(f.lat)]};else if(k==='routes')geom={type:'LineString',coordinates:coords.map(c=>[Number(c[1]??c.lon),Number(c[0]??c.lat)]).filter(c=>Number.isFinite(c[0])&&Number.isFinite(c[1]))};else geom={type:'Polygon',coordinates:[coords.map(c=>[Number(c[1]??c.lon),Number(c[0]??c.lat)]).filter(c=>Number.isFinite(c[0])&&Number.isFinite(c[1]))]}}else if(f.lat!=null&&f.lon!=null){geom={type:'Point',coordinates:[Number(f.lon),Number(f.lat)]}}return{type:'Feature',geometry:geom,properties:{name:f.name||f.callsign||f.title||'',source:f.import_name||f.source||'',kind:kind}}}).filter(x=>x.geometry)};if(!gj.features.length){alert('No exportable geometry found for the selected item(s).');return}const blob=new Blob([JSON.stringify(gj,null,2)],{type:'application/geo+json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=localDataExportFilename(kind,feats);document.body.appendChild(a);a.click();setTimeout(()=>{URL.revokeObjectURL(a.href);a.remove()},500)}catch(e){alert('Export failed: '+e)}}function localDataPublishTitle(kind,ids){const map={points:'Point',routes:'Route',shapes:'Shape'};const one=(ids||[]).length===1;return 'Publish '+(one?(map[kind]||'Item'):(map[kind]||'Item')+'s')+' to Data Sync/Mission'}
function openLocalDataPublish(kind,ids){activeSendMode='local-data-publish';activeLocalSendKind=kind;activeLocalSendIds=(ids||[]).slice();const modal=document.getElementById('sendModal');const title=document.querySelector('#sendModal h3');const name=document.getElementById('sendMapName');const details=document.getElementById('sendMapDetails');const status=document.getElementById('sendStatus');if(title)title.textContent=localDataPublishTitle(kind,ids);if(name)name.textContent='Publish '+ids.length+' selected local '+kind+' item(s) into a Data Sync Mission.';if(details)details.innerHTML='<div class="send-map-summary">Type: '+esc(kind)+'<br>Selected: '+esc(ids.length)+'<br><small>This creates a TAK Mission Package containing KML and GeoJSON for the selected local item(s).</small></div>';if(status)status.textContent='';if(modal)modal.classList.add('active');loadSendMissions()}
function centerLocalItem(kind,id,ev){if(ev)ev.stopPropagation();const f=localDataFeatureById(id);const cen=objectCenter(f);if(!f||!cen){alert('No valid coordinates found for this local item.');return}try{map.panTo(cen,{animate:true});if(f.__layer){setTimeout(()=>{try{f.__layer.openPopup()}catch(e){}},160)}}catch(e){try{console.warn('centerLocalItem failed',e)}catch(_){}}}
function centerSelectedLocal(kind,ids){const pts=[];for(const id of (ids||[])){const f=localDataFeatureById(id);const cen=objectCenter(f);if(cen)pts.push(cen)}if(!pts.length){alert('No valid coordinates found for the selected item(s).');return}try{if(pts.length===1)map.panTo(pts[0],{animate:true});else map.fitBounds(L.latLngBounds(pts).pad(.22))}catch(e){try{console.warn('centerSelectedLocal failed',e)}catch(_){}}}
async function localDataAction(kind,action){const ids=selectedLocal(kind);if(!ids.length){alert('Select one or more '+localTypeLabel(kind,2)+' first.');return}if(action==='goto'){centerSelectedLocal(kind,ids);return}if(action==='hide'||action==='show'){for(const id of ids){state.local.hidden[id]=(action==='hide')}renderLocalDataRows();drawImportedObjects();return}if(action==='export'){downloadLocalData(kind,ids);return}if(action==='publish'){openLocalDataPublish(kind,ids);return}if(action==='delete'){if(!confirm('Delete '+localSelectedLabel(kind,ids.length)+'?'))return;try{const r=await fetch('/api/tak-map/local-data-delete',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({ids})});const j=await r.json();if(!r.ok||!j.ok)throw new Error(j.error||('HTTP '+r.status));lastImports=j.imports||lastImports;state.local[kind]={};renderLocalDataRows();drawImportedObjects();return}catch(e){alert('Delete failed: '+e);return}}}
function renderLocalActions(kind,items){const ids=selectedLocal(kind);if(!ids.length)return'';const allHidden=ids.every(id=>!!state.local.hidden[id]);const hideShow=allHidden?'Show':'Hide';return `<div class="local-actions ${kind}"><div class="local-actions-top"><span id="localActionCount_${kind}" class="muted local-selected-count">${esc(localSelectedLabel(kind,ids.length))}</span></div><div class="local-action-buttons"><button class="layer-button" onclick="localDataAction('${kind}','goto')">Go To</button><button class="layer-button" onclick="localDataAction('${kind}','publish')">Publish</button><button class="layer-button" onclick="localDataAction('${kind}','export')">Export</button><button class="layer-button" onclick="localDataAction('${kind}','${hideShow.toLowerCase()}')">${hideShow}</button><button class="layer-button" onclick="localDataAction('${kind}','delete')">Delete</button></div></div>`}
function renderLocalSection(kind,title,items){const collapsed=!!state.localCollapsed[kind];let html=`<div class="local-section ${collapsed?'collapsed':''}"><div class="subgroup-title local-section-title" onclick="toggleLocalSection('${kind}')"><span class="subgroup-label"><span class="toggle">${collapsed?'›':'⌄'}</span>${esc(title)}</span><span class="chip">${items.length}</span><button class="layer-button unselect-local-btn" onclick="unselectLocalSection('${kind}',event)">Unselect All</button></div><div class="local-data-list">`;html+=items.length?items.slice(0,120).map(it=>{const checked=state.local[kind][it.id]?'checked':'';const vis=it.shown===false?'hidden':'shown';const colorCtl='';const coords=(kind==='points'&&it.lat!=null&&it.lon!=null)?formatCoords(it.lat,it.lon):'';const meta=coords||((it.source||'Local Data')+' · '+vis);return`<div class="local-data-row ${checked?'selected-local':''} ${vis==='hidden'?'hidden-local':''}"><label class="local-data-main"><input type="checkbox" ${checked} onchange="toggleLocalItem('${kind}','${esc(it.id)}',this.checked)"><span><b>${esc(it.name)}</b><small>${esc(meta)}</small></span></label><button class="layer-button local-goto-btn" onclick="centerLocalItem('${kind}','${esc(it.id)}',event)">Go To</button>${colorCtl}</div>`}).join(''):'<div class="muted" style="padding:8px">No local '+esc(title.toLowerCase())+' yet.</div>';html+=`</div>${renderLocalActions(kind,items)}</div>`;return html}function triggerLocalAdd(kind){const inp=document.getElementById('importFileInput');if(inp){inp.dataset.localKind=kind;inp.value='';inp.click();return}alert('Import control is not available.')}async function refreshLocalData(){try{renderLocalDataRows();return {ok:true}}catch(e){renderLocalDataRows(String(e));return {ok:false,error:String(e)}}}
function renderLocalDataRows(err){const box=document.getElementById('localDataRows');if(!box)return;const sets=localDataSets();const total=sets.routes.length+sets.points.length+sets.shapes.length;const chip=document.getElementById('localDataCount');if(chip)chip.textContent=String(total);let html='';if(err)html+='<div class="danger">'+esc(err)+'</div>';html+=`<div class="local-add-grid"><button class="layer-button" onclick="triggerLocalAdd('points')">+ Add Point</button><button class="layer-button" onclick="triggerLocalAdd('routes')">+ Add Route</button><button class="layer-button" onclick="triggerLocalAdd('shapes')">+ Add Shape</button></div>`;html+=renderLocalSection('points','Points',sets.points);html+=renderLocalSection('routes','Routes',sets.routes);html+=renderLocalSection('shapes','Shapes',sets.shapes);box.innerHTML=html}function renderRouteRows(){renderLocalDataRows()}function toggleRoute(idx,on){const r=(lastRoutes||[])[idx];if(!r)return;state.routes[r.path]=on;if(!on&&routeLayers[r.path]){map.removeLayer(routeLayers[r.path]);delete routeLayers[r.path];return}if(on){alert('Route file listing is active. Direct overlay rendering will be wired to Local Data actions.')}}
