  function getRadius(){return clamp($('adsbRadiusMilesV281')?.value||stored('radius','50'),1,250,50)}
  function getInterval(){return clamp($('adsbUpdateIntervalV281')?.value||stored('interval','10'),5,300,10)}
  function getCenterSource(){return $('adsbCenterSourceV281')?.value||stored('centerSource','manual')}
  function parseCenter(){const val=($('adsbCenterLatLonV281')?.value||stored('center','')).trim();const m=val.match(/(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)/);if(!m)return null;const lat=Number(m[1]),lon=Number(m[2]);return Number.isFinite(lat)&&Number.isFinite(lon)&&Math.abs(lat)<=90&&Math.abs(lon)<=180?{lat,lon}:null}
  function writeCenter(lat,lon){const text=Number(lat).toFixed(6)+', '+Number(lon).toFixed(6);const el=$('adsbCenterLatLonV281');if(el)el.value=text;put('center',text)}
