    $('adsbCenterSourceV281').addEventListener('change',()=>{put('centerSource',$('adsbCenterSourceV281').value); if(getCenterSource()==='follow_map_center'&&window.map){const c=map.getCenter();writeCenter(c.lat,c.lng)} if(adsbEnabled)schedulePoll(400)});
