    ['Civil','Military','Govt','Unknown'].forEach(name=>{const el=$('adsbFilter'+name+'V281'); el.addEventListener('change',()=>{put('filter'+name,el.checked?'1':'0'); drawAircraft(window.lastAircraft||[])})});
