  function getWorker(){if(adsbWorker)return adsbWorker;adsbWorker=new Worker(URL.createObjectURL(new Blob([workerScript()],{type:'text/javascript'})));adsbWorker.onmessage=ev=>{const d=ev.data||{},job=adsbJobs[d.id];if(!job)return;delete adsbJobs[d.id];d.ok?job.resolve(d.all||[]):job.reject(new Error(d.error||'fetch failed'))};return adsbWorker;}
