  function drawAircraft(list){if(!adsbEnabled)return;const layer=ensureLayer();if(!layer)return;const shown=filtered(list),seen=new Set();for(const a of shown){if(!Number.isFinite(Number(a.lat))||!Number.isFinite(Number(a.lon)))continue;const id=String(a.id||a.hex||a.callsign).toLowerCase();seen.add(id);const ll=[Number(a.lat),Number(a.lon)],url=iconFor(a),rot=Number(a.track_deg)||0,label=esc(a.callsign||a.registration||a.hex||'ADS-B');let m=markers.get(id);if(!m){const icon=L.divIcon({className:'adsb-v284-marker',iconSize:[90,44],iconAnchor:[45,18],html:`<div class="aircraft-wrap"><img src="${esc(url)}" style="transform:rotate(${rot}deg)"><span class="aircraft-label">${label}</span></div>`});m=L.marker(ll,{icon,zIndexOffset:900,interactive:true}).addTo(layer);m.bindPopup(popupHtml(a),{className:'adsb-v284-popup adsb-object-popup',autoPan:false,closeButton:true});m.on('mouseover',()=>{if(!pinnedAdsb)try{m.openPopup()}catch(_){}});m.on('mouseout',()=>{if(!pinnedAdsb)try{m.closePopup()}catch(_){}});m.on('click',ev=>{try{L.DomEvent.stop(ev);pinnedAdsb=id;m.openPopup()}catch(_){}});markers.set(id,m)}else{m.setLatLng(ll);const el=m.getElement();if(el){const img=el.querySelector('img'),lab=el.querySelector('.aircraft-label');if(img){if(img.getAttribute('src')!==url)img.setAttribute('src',url);img.style.transform=`rotate(${rot}deg)`}if(lab&&lab.textContent!==label)lab.textContent=label}if(!m.isPopupOpen()||pinnedAdsb!==id){try{m.setPopupContent(popupHtml(a))}catch(_){}}}} for(const [id,m] of markers){if(!seen.has(id)){try{layer.removeLayer(m)}catch(_){ } markers.delete(id); if(pinnedAdsb===id)pinnedAdsb=null}} try{if($('adsbStatus'))$('adsbStatus').textContent=shown.length+' active'; if($('bannerAdsb'))$('bannerAdsb').textContent=shown.length+' Aircraft'}catch(_){ }}
  function bindMap(){if(window.map&&!window._v284MapBound){window._v284MapBound=true;map.on('movestart zoomstart dragstart move zoom drag',markInteraction);map.on('moveend zoomend',()=>{markInteraction();if(adsbEnabled&&getCenterSource()==='follow_map_center'){const c=map.getCenter();writeCenter(c.lat,c.lng);schedulePoll(900)}});map.on('click',()=>{pinnedAdsb=null})}const side=$('sidebar');if(side&&!side.dataset.v284Scroll){side.dataset.v284Scroll='1';side.addEventListener('scroll',markInteraction,{passive:true})}}
