  function ensureViewshedButton(){try{const bar=$('floatingMapToolbar')||q('.floating-map-toolbar');if(!bar)return;qa('#toolViewshed').forEach((n,i)=>{if(i>0)n.remove()});let btn=$('toolViewshed');if(!btn){btn=document.createElement('button');btn.id='toolViewshed';btn.className='tool-btn';btn.type='button';btn.title='Viewshed';btn.innerHTML='<svg viewBox="0 0 24 24"><path d="M3 18c5-8 13-8 18 0"/><path d="M6 18c3-5 9-5 12 0"/><circle cx="12" cy="10" r="2"/></svg><span class="tool-label">Viewshed</span>';const anchor=$('tool3d')||$('toolClearHidden')||$('toolFit');if(anchor&&anchor.parentElement===bar)bar.insertBefore(btn,anchor);else bar.appendChild(btn)}btn.onclick=function(ev){try{ev&&ev.stopPropagation&&ev.stopPropagation()}catch(_){ } if(typeof toggleViewshedModule==='function')toggleViewshedModule(); return false}}catch(_){ }}
  function ensureTerrainIncline(){try{if($('terrainInclineSliderV281'))return;const host=q('.terrain3d-controls')||$('terrain3dPane');if(!host)return;const wrap=document.createElement('div');wrap.className='terrain-incline-control';wrap.innerHTML='<label for="terrainInclineSliderV281">View Incline</label><input id="terrainInclineSliderV281" type="range" min="15" max="80" step="1" value="55"><span id="terrainInclineValueV281">55°</span><button type="button" class="terrain-incline-reset layer-button">Reset</button>';host.appendChild(wrap);const slider=$('terrainInclineSliderV281'),val=$('terrainInclineValueV281');function apply(){const deg=Number(slider.value)||55;if(val)val.textContent=deg+'°';try{if(typeof terrain3DViewer!=='undefined'&&terrain3DViewer&&terrain3DViewer.camera){const cam=terrain3DViewer.camera;const h=cam.heading||0;cam.setView({orientation:{heading:h,pitch:-(deg*Math.PI/180),roll:0}});terrain3DViewer.scene&&terrain3DViewer.scene.requestRender&&terrain3DViewer.scene.requestRender()}}catch(_){ }}slider.addEventListener('input',apply);wrap.querySelector('button').onclick=()=>{slider.value='55';apply()};}catch(_){ }}
  function formHygiene(){try{const seen={};qa('[id]').forEach(el=>{if(!el.id)return;if(seen[el.id]){el.id=el.id+'__dup'+Math.random().toString(36).slice(2,7)}seen[el.id]=1});qa('label').forEach((lab,i)=>{if(lab.control||lab.querySelector('input,select,textarea'))return;const ctl=lab.parentElement&&lab.parentElement.querySelector('input,select,textarea');if(ctl){if(!ctl.id)ctl.id='takFieldV281_'+i;lab.setAttribute('for',ctl.id)}})}catch(_){ }}
